parameters.jsCode:
const body = $('Webhook').item.json.body || {};
const orden = body.orden || {};
const etapas = body.etapas || [];

return etapas
  .filter(e => e.tecnico && e.tecnico !== 'Sin asignar')
  .map(e => ({
    json: {
      tecnico_nombre: e.tecnico,
      etapa_nombre: e.etapa || e.nombre || 'Etapa',
      servicio: e.servicio || 'Sin servicio',
      placa: orden.placa || body.placa || 'Sin placa',
      marca: orden.marca || body.marca || '',
      linea: orden.linea || body.modelo || '',
      propietario: orden.propietario || body.propietario || 'Sin propietario',
      fecha_entrega: orden.fecha_entrega_1 || body.fecha_entrega || null,
      link: body.link || ''
    }
  }));

